Concrete C++ implementation of binary search on a sorted vector. Returns the index of target, or -1 if not present. Uses the overflow-safe midpoint and the inclusive [lo, hi] invariant.

#include <vector>

int binary_search(const std::vector<int>& a, int target) {
    int lo = 0;
    int hi = static_cast<int>(a.size()) - 1;
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        if (a[mid] == target) return mid;
        if (a[mid] < target) lo = mid + 1;
        else                 hi = mid - 1;
    }
    return -1;
}
